import React from 'react';

interface Order {
  id: string;
  customerName: string;
  totalAmount: number;
  status: 'pending' | 'shipped' | 'completed';
  onStatusChange: (id: string, status: 'pending' | 'shipped' | 'completed') => void;
}

interface OrderListProps {
  orders: Order[];
}

const OrderList: React.FC<OrderListProps> = ({ orders }) => {
  return (
    <div className="bg-gray-900 p-6 rounded-xl shadow-md">
      <h2 className="text-2xl font-semibold text-white mb-4">Order Management</h2>
      {orders.length === 0 ? (
        <p className="text-gray-400">No orders yet. Start by adding products!</p>
      ) : (
        <table className="w-full text-left">
          <thead>
            <tr>
              <th className="text-gray-400">Customer</th>
              <th className="text-gray-400">Total</th>
              <th className="text-gray-400">Status</th>
              <th className="text-gray-400">Actions</th>
            </tr>
          </thead>
          <tbody>
            {orders.map(order => (
              <tr key={order.id} className="border-b border-gray-800">
                <td className="text-white py-2">{order.customerName}</td>
                <td className="text-white">${order.totalAmount.toFixed(2)}</td>
                <td className="text-white">
                  <select
                    value={order.status}
                    onChange={(e) => order.onStatusChange(order.id, e.target.value as 'pending' | 'shipped' | 'completed')}
                    className="bg-gray-800 text-white rounded-lg"
                  >
                    <option value="pending">Pending</option>
                    <option value="shipped">Shipped</option>
                    <option value="completed">Completed</option>
                  </select>
                </td>
                <td className="text-white">
                  <button className="px-4 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-500 transition">
                    View
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default OrderList;
